mapper.select:
SELECT a.activity_id AS activityId, a.title, a.summary, a.cover_url AS coverUrl, a.location, a.start_time AS startTime, a.end_time AS endTime, a.capacity, a.joined_count AS joinedCount, CASE WHEN #{userId} IS NULL OR #{userId} = '' THEN FALSE WHEN EXISTS ( SELECT 1 FROM group_activity_join j WHERE j.activity_id = a.activity_id AND j.user_id = #{userId} AND j.join_status = 'JOINED' ) THEN TRUE ELSE FALSE END AS joined FROM group_activity a
AND a.status = #{q.status}
AND a.status = 'PUBLISHED'
AND (a.title LIKE CONCAT('%', #{q.keyword}, '%') OR a.summary LIKE CONCAT('%', #{q.keyword}, '%'))
AND a.start_time >= #{q.startTime}
AND a.start_time <= #{q.endTime}
ORDER BY a.start_time DESC
